const content = $input.item.json?.message?.content ?? {};
const now = new Date().toISOString().split('T')[0];

return {
  json: {
    Organization_name: content.Organization_name || '',
    CEO_LinkedIn: content.CEO_LinkedIn || '',
    CEO_First_name: content.CEO_First_name || '',
    CEO_Last_name: content.CEO_Last_name || '',
    LinkedIn_message: content.connection_request || '',
    First_message: content.first_message || '',
    First_nudge: content.first_nudge || '',
    Second_nudge: content.second_nudge || '',
    message_stage: 'connection_request_generated',
    messages_generated_date: now
  }
};
